import os
from prometheus_client import Gauge, start_http_server

# Set up the Prometheus client
REGISTRY = Gauge('database_credentials', 'Database credentials')

def monitor_database():
    # Get the database credentials from environment variables
    username = os.environ['DB_USERNAME']
    password = os.environ['DB_PASSWORD']
    host = os.environ['DB_HOST']
    connection_string = os.environ['DB_CONNECTION_STRING']

    # Set the gauge metric with the current timestamp and the database credentials as labels
    REGISTRY.labels(username=username, password=password, host=host, connection_string=connection_string).set_to_current_time()

if __name__ == '__main__':
    # Start the Prometheus HTTP server
    start_http_server(8000)

    # Monitor the database credentials every 10 seconds
    while True:
        monitor_database()
        time.sleep(10)